import React, { useState } from "react";
import axios from "axios";

const API_URL = "http://localhost:5000/api/analyze";

function Dashboard() {
  const [logs, setLogs] = useState("");
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const isLegacyResponse =
    result &&
    (!Object.prototype.hasOwnProperty.call(result, "analyzerVersion") ||
      !Array.isArray(result.issues) ||
      !Object.prototype.hasOwnProperty.call(result, "issueCount"));

  const analyze = async () => {
    setError("");
    setResult(null);

    const cleanedLogs = logs.trim();

    if (!cleanedLogs) {
      setError("Paste logs before analyzing.");
      return;
    }

    if (/^https?:\/\/\S+\/api\/\S*$/i.test(cleanedLogs)) {
      setError("Paste the actual logs or stack trace here, not the API URL.");
      return;
    }

    try {
      setIsAnalyzing(true);
      const res = await axios.post(API_URL, {
        logs: cleanedLogs
      });

      setResult(res.data);
    } catch (error) {
      console.error("Error:", error);
      setError(
        error.response?.data?.suggestion ||
          "Unable to analyze logs right now. Check that the backend is running on port 5000."
      );
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div style={{ maxWidth: "900px" }}>
      <p>
        Paste raw logs, stack traces, or terminal errors here. Do not paste the
        API URL itself.
      </p>

      <textarea
        placeholder={
          "Example:\nFATAL ERROR: Reached heap limit Allocation failed - JavaScript heap out of memory\nor\nError: connect ECONNREFUSED 127.0.0.1:5432"
        }
        value={logs}
        onChange={(e) => setLogs(e.target.value)}
        rows={10}
        style={{ width: "100%", fontFamily: "monospace" }}
      />

      <button onClick={analyze} disabled={isAnalyzing}>
        {isAnalyzing ? "Analyzing..." : "Analyze"}
      </button>

      {error && <p>{error}</p>}

      {isLegacyResponse && (
        <p>
          The backend server is running old analyzer code. Restart the backend
          on port 5000 and try again.
        </p>
      )}

      {result && (
        <div style={{ marginTop: "24px" }}>
          <h3>
            {result.issueCount > 0
              ? `Detected ${result.issueCount} Issue${result.issueCount > 1 ? "s" : ""}`
              : `Issue: ${result.issue}`}
          </h3>
          <p>Primary issue: {result.issue}</p>
          <p>Highest severity: {result.severity || "Unavailable from current backend response"}</p>
          <p>
            Summary:{" "}
            {result.summary || "The current backend did not return a detailed diagnosis."}
          </p>
          <p>Suggestion: {result.suggestion}</p>
          {result.categories?.length > 0 && (
            <p>Categories: {result.categories.join(", ")}</p>
          )}
          {result.analyzerVersion && (
            <p>Analyzer version: {result.analyzerVersion}</p>
          )}
          {result.engine && <p>Engine: {result.engine}</p>}
          {result.model && <p>Model: {result.model}</p>}
          {result.fallbackReason && (
            <p>Fallback reason: {result.fallbackReason}</p>
          )}

          {result.issues?.length > 0 && (
            <div style={{ marginTop: "24px" }}>
              <h4>Detected Issues</h4>

              {result.issues.map((issue) => (
                <div
                  key={issue.id}
                  style={{
                    border: "1px solid #cccccc",
                    padding: "16px",
                    marginBottom: "16px",
                    borderRadius: "8px"
                  }}
                >
                  <h5 style={{ margin: "0 0 12px 0" }}>{issue.issue}</h5>
                  <p style={{ margin: "0 0 8px 0" }}>
                    Severity: {issue.severity}
                  </p>
                  <p style={{ margin: "0 0 8px 0" }}>
                    Category: {issue.category}
                  </p>
                  <p style={{ margin: "0 0 8px 0" }}>
                    Summary: {issue.summary}
                  </p>
                  <p style={{ margin: "0 0 8px 0" }}>
                    Suggestion: {issue.suggestion}
                  </p>

                  {issue.evidence?.length > 0 && (
                    <div>
                      <h6 style={{ margin: "12px 0 8px 0" }}>Evidence</h6>
                      <ul>
                        {issue.evidence.map((line, index) => (
                          <li key={`${issue.id}-${index}`}>
                            <code>{line}</code>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}

          {result.issueCount === 0 && result.evidence?.length > 0 && (
            <div>
              <h4>Evidence</h4>
              <ul>
                {result.evidence.map((line, index) => (
                  <li key={`${line}-${index}`}>
                    <code>{line}</code>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default Dashboard;
